mapper.select:
	SELECT	* 



 		ORDER BY	COUNT ${sortDirect}


 		ORDER BY	PM_NAME ${sortDirect}


 		ORDER BY	PM_NAME_EN ${sortDirect}


 		ORDER BY	PM_SEAT ${sortDirect}


 		ORDER BY	PM_USE ${sortDirect}


 		ORDER BY	PM_SEATPLAN_YN ${sortDirect}


 		ORDER BY	COUNT DESC



	LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}

SELECT @ROWNUM := @ROWNUM + 1 AS NUMBER ,AA.* FROM ( SELECT P.* , FS.FS_KEYNO FS_KEYNO1 , FS.FS_ORINM FS_ORINM1 , CONCAT(FS.FS_FOLDER, FS.FS_CHANGENM, '.', FS.FS_EXT) THUMBNAIL_PATH , FS.FS_PUBLIC_PATH THUMBNAIL_PUBLIC_PATH , FS2.FS_KEYNO FS_KEYNO2 , FS2.FS_ORINM FS_ORINM2 , CONCAT(FS2.FS_FOLDER, FS2.FS_CHANGENM, '.', FS2.FS_EXT) SEATBACKGROUND_PATH , FS.FS_PUBLIC_PATH SEATBACKGROUND_PUBLIC_PATH FROM t_place_manager P LEFT JOIN s_common_file_sub FS ON P.PM_FS_KEYNO = FS.FS_KEYNO LEFT JOIN s_common_file_sub FS2 ON P.PM_SEAT_FS_KEYNO = FS2.FS_KEYNO WHERE PM_USE != 'D' ORDER BY PM_KEYNO ) AA, (SELECT @ROWNUM := 0 ) R
WHERE PM_KEYNO = #{PM_KEYNO}
ORDER BY PM_KEYNO DESC

mapper.insert:
INSERT INTO t_place_manager(
		PM_KEYNO
	,	PM_NAME
	,   PM_NAME_EN
	,	PM_FS_KEYNO
	,	PM_USE
	,	PM_SEAT
	,	PM_SEATPLAN_YN
	,	PM_SEATPLAN_WIDTH
	,	PM_SEATPLAN_HEIGHT
	,	PM_SEAT_FS_KEYNO
) VALUES (
		#{PM_KEYNO}
	,	#{PM_NAME}
	,	#{PM_NAME_EN}
	,	#{PM_FS_KEYNO}
	,	#{PM_USE}
	,	#{PM_SEAT}
	,	#{PM_SEATPLAN_YN}
	,	#{PM_SEATPLAN_WIDTH}
	,	#{PM_SEATPLAN_HEIGHT}
	,	#{PM_SEAT_FS_KEYNO}
)

mapper.update:
UPDATE t_place_manager
SET		PM_NAME				=	#{PM_NAME}
	  , PM_NAME_EN			=	#{PM_NAME_EN}
	  , PM_FS_KEYNO			=	#{PM_FS_KEYNO}
	  , PM_USE				=	#{PM_USE}
	  , PM_SEAT				=	#{PM_SEAT}
	  , PM_SEATPLAN_YN		=	#{PM_SEATPLAN_YN}
	  , PM_SEATPLAN_WIDTH	=	#{PM_SEATPLAN_WIDTH}
	  , PM_SEATPLAN_HEIGHT	=	#{PM_SEATPLAN_HEIGHT}
	  ,	PM_SEAT_FS_KEYNO	=	#{PM_SEAT_FS_KEYNO}
WHERE	PM_KEYNO			=	#{PM_KEYNO}

UPDATE t_place_manager
SET		PM_USE		=	'D'
WHERE	PM_KEYNO	=	#{PM_KEYNO}

