mapper.delete:
DELETE FROM t_place_seatgroup_sub
WHERE	PSS_PSM_KEYNO	IN (
	SELECT 	PSM_KEYNO
	FROM t_place_seatgroup_main
	WHERE	PSM_PM_KEYNO	=	#{PM_KEYNO}	
)
